INSERT INTO Activity (title, description, duration, supplies, min_age) VALUES
('Sensory Rice Bin', 'Fill a bin with colored rice and hide small toys inside for your toddler to discover. This activity promotes fine motor skills, sensory exploration, and problem-solving as children dig through the rice to find hidden treasures. Great for keeping little ones engaged and curious about textures and colors.', 20, 'Rice, food coloring, small toys, plastic bin, measuring cups, spoons', 12),
('Finger Painting Fun', 'Let your child explore colors and textures with washable finger paints on large paper. Encourage them to mix colors and make patterns.', 30, 'Washable finger paints, large paper or cardboard, smock or old shirt, wet wipes', 18),
('Nature Walk Scavenger Hunt', 'Take a walk outside and look for leaves, rocks, flowers, and bugs. Talk about what you find and encourage your child to collect safe natural items in a bag.', 45, 'Paper bag, magnifying glass', 24),
('Playdough Creations', 'Roll, squish, and shape homemade or store-bought playdough. Use cookie cutters and rolling pins to create shapes and figures.', 25, 'Playdough, cookie cutters, rolling pin, plastic knife, textured items for stamping', 18),
('Water Pouring Station', 'Set up cups, funnels, and containers at a water table or in the bathtub. Let your child practice pouring water between containers to develop hand-eye coordination and concentration.', 20, 'Cups, funnels, plastic containers, towel, food coloring (optional)', 15),
('Stacking Blocks', 'Build towers and knock them down! Start with large soft blocks for younger toddlers and progress to smaller wooden blocks as coordination improves.', 15, 'Soft blocks or wooden blocks', 6),
('Bubble Play', 'Blow bubbles outside and encourage your child to chase, pop, and catch them. Great for gross motor development and outdoor fun.', 15, NULL, 6),
('Musical Shaker Bottles', 'Fill empty water bottles with rice, beans, or beads and seal tightly. Let your child shake them to make music and explore different sounds.', 10, 'Empty water bottles, rice, dried beans, beads, strong tape or glue', 9),
('Obstacle Course', 'Create a simple indoor or outdoor obstacle course using pillows, tunnels, chairs, and blankets. Guide your child through crawling, climbing, and balancing activities that build gross motor skills and confidence.', 30, 'Pillows, chairs, blankets, pool noodles, hula hoops', 18),
('Tummy Time with Toys', 'Place colorful toys just out of reach during tummy time to encourage reaching, grasping, and strengthening neck and core muscles.', 10, NULL, 0),
('Color Sorting Activity', 'Use colored cups or bowls and small objects like pom-poms or buttons. Have your child sort items by color to learn color recognition and practice fine motor skills.', 20, 'Colored cups or bowls, pom-poms, buttons, tongs or tweezers', 24),
('Simple Cooking: Banana Smoothie', 'Let your child help add ingredients to a blender for a healthy banana smoothie. They can peel bananas, measure yogurt, and press the blender button with supervision.', 15, 'Bananas, yogurt, milk, blender, measuring cups', 30),
('Gardening with Toddlers', 'Plant seeds in small pots or a garden bed. Let your child dig in the soil, water the plants, and watch them grow over time. Teaches responsibility and patience.', 40, 'Small pots, soil, seeds, watering can, small shovel', 24),
('Collage Making', 'Cut out pictures from magazines or use stickers, tissue paper, and glue to create a collage. Develops fine motor skills, creativity, and decision-making as children choose and place materials on their paper.', 30, 'Magazines, scissors (child-safe), glue stick, construction paper, stickers, tissue paper, googly eyes, yarn scraps', 30),
('Dancing and Movement', 'Put on your child''s favorite music and dance together! Try freeze dance, animal walks, or follow-the-leader to build body awareness and coordination.', 20, NULL, 9),
('Sand Play', 'Visit a sandbox or create one at home. Use shovels, molds, and trucks to dig, build, and explore the texture of sand.', 30, 'Sandbox or bin with sand, shovels, molds, toy trucks, spray bottle with water', 12),
('Reading Time', 'Read board books together, pointing at pictures and naming objects. Let your child turn the pages and choose which books to read.', 15, NULL, 3),
('Baking Cookies Together', 'Follow a simple cookie recipe with your child helping to stir, pour, and use cookie cutters. A wonderful practical life activity that teaches measuring, following steps, and patience while waiting for cookies to bake in the oven.', 60, 'Flour, sugar, butter, eggs, vanilla, cookie cutters, mixing bowl, baking sheet, oven mitts', 36),
('Threading and Lacing', 'Use large wooden beads or pasta with thick string or shoelaces to practice threading. Builds fine motor control, hand-eye coordination, and concentration.', 20, 'Large wooden beads or dried penne pasta, thick string or shoelaces', 30),
('Science Experiment: Baking Soda Volcano', 'Create a mini volcano using baking soda and vinegar. Add food coloring for a colorful eruption. Talk about what happens when the ingredients mix and why it fizzes. This classic experiment never fails to delight curious toddlers and introduces basic cause-and-effect concepts in a hands-on, memorable way.', 15, 'Baking soda, vinegar, food coloring, dish soap, container or cup, tray to catch overflow', 30),
('Ball Pit Play', 'Fill a small inflatable pool or large box with plastic balls. Let your child climb in, throw, and sort the balls by color.', 25, 'Plastic balls, inflatable pool or large cardboard box', 9),
('Washing Dishes', 'Set up a small basin with warm soapy water and let your child wash plastic dishes and utensils. A Montessori-inspired practical life activity.', 20, 'Small basin, warm water, dish soap, sponge, plastic dishes and utensils, towel', 24),
('Chalk Drawing', 'Use sidewalk chalk to draw pictures, trace shapes, or write letters on the driveway or sidewalk. Encourage your child to explore colors and try drawing familiar objects.', 30, 'Sidewalk chalk', 18),
('Puzzle Time', 'Work on age-appropriate puzzles together. Start with simple knob puzzles for younger toddlers and progress to jigsaw puzzles with more pieces.', 20, 'Age-appropriate puzzles (knob puzzles, jigsaw puzzles)', 12),
('Ice Painting', 'Freeze water with food coloring in ice cube trays with popsicle sticks. Once frozen, let your child paint on paper with the colored ice cubes as they melt.', 25, 'Ice cube trays, food coloring, popsicle sticks, paper, smock', 18),
('Yoga for Toddlers', 'Practice simple yoga poses together like tree, cat-cow, and downward dog. Use animal names to make it fun and engaging. Great for body awareness, balance, and calming energy.', 15, NULL, 24),
('Pouring and Scooping with Beans', 'Fill a bin with dried beans and provide cups, spoons, and funnels. Let your child practice pouring and scooping, developing concentration and coordination.', 20, 'Dried beans, cups, spoons, funnels, plastic bin', 15),
('Cardboard Box Play', 'Give your child a large cardboard box and let their imagination run wild. It can become a car, a house, a spaceship, or a boat. Add crayons for decorating.', 45, NULL, 12),
('Simple Science: Sink or Float', 'Gather household objects and a basin of water. Have your child predict whether each item will sink or float, then test it together. Introduces scientific thinking and observation skills.', 20, 'Basin of water, assorted household objects (cork, coin, sponge, rock, plastic toy, feather, spoon), towel', 30),
('Music and Instruments', 'Explore different musical instruments like drums, tambourines, xylophones, and maracas. Play along to songs and experiment with rhythm, tempo, and volume. Develops auditory awareness and coordination through creative musical exploration that toddlers absolutely love.', 20, 'Drums, tambourines, xylophone, maracas (or homemade instruments)', 12);
